@namespace "WutAvatar";

:import {
  -st-from: "/c55774f4e58854631dbb8aa1d99fc4819653626f.st.css";
  -st-default: AvatarBase;
}

:import {
  -st-from: '../../../../common/stylable/params.js';
  -st-named: getVar;
}

.avatarWrapper {
  width: auto !important;
  height: auto !important;
}

.root {
  -st-extends: AvatarBase;
  --circleSize: 36px;
  background: #d8d8d8;
  color: #979797;

  /* We need to wrap the --corvid-circleSize with the getVar formatter method since it is set in the corvid file without the Stylable namespace (prefix). */
  width: getVar(--corvid-circleSize, var(--circleSize));
  height: getVar(--corvid-circleSize, var(--circleSize));
}
.root::before {
  /*
    WUT avatar text is rendered in a before pseudo element with absolute positioning which seems to break inheriting of some properties,
    so we need to set this for inheritance to work.
  */
  text-decoration: inherit;
}

.dummy-class-for-ci-fix {
  display: block;
}

