@namespace "WutAvatarGroup";

:import {
  -st-from: "/c55774f4e58854631dbb8aa1d99fc4819653626f.st.css";
  -st-default: AvatarBase;
}

:import {
  -st-from: '../../../../common/stylable/params.js';
  -st-named: getVar;
}

.avatarContainerLayout {
  height: auto !important;
  width: auto !important;
}

.root {
  display: inline-flex;
  flex-direction: row;
  --avatarCircleSize: 36px;
  --spaceSize: 8px;
  --overlap: -1;
}

.avatarContainer {
  margin-inline-start: calc(var(--overlap) * var(--spaceSize));
  overflow: visible;
}

.avatarContainer:first-of-type {
  margin-inline-start: 0;
}

.avatarWrapper {
  width: fit-content;
  height: fit-content;
  border-radius: 50%;
}

.avatar {
  -st-extends: AvatarBase;
  background: #d8d8d8;

  border: 2px solid white;
  border-radius: inherit !important;
  width: getVar(--corvid-avatarCircleSize, var(--avatarCircleSize));
  height: getVar(--corvid-avatarCircleSize, var(--avatarCircleSize));
}
.avatar::before {
  /*
    WUT avatar text is rendered in a before pseudo element with absolute positioning which seems to break inheriting of some properties,
    so we need to set this for inheritance to work.
  */
  text-decoration: inherit;
}

.avatar::image {
  display: flex;
  align-items: center;
  justify-content: center;
  max-height: 100%;
}

