@namespace "WutBadge";

:import {
    -st-from: '../../../../common/stylable/params.js';
    -st-named: getVar;
}

:import {
    -st-from: "/cc17b6fbbf975482159464b8d96bef7068c1e155.st.css";
    -st-default: BadgeBase;
}

:vars {
    icon-position: getVar(--icon-position);
    spacing: getVar(--spacing);
    rootWidth: getVar(--root-width);
    rootHeight: getVar(--root-height);
    wrapperWidth: getVar(--wrapper-height);
    wrapperHeight: getVar(--wrapper-height);
}

.root{
    -st-extends: BadgeBase;
    display: flex;
    padding: 2px 12px;
    justify-content: center;
    align-items: center;
    border-radius: 8px;
    background: #7247ff1a;
    width: value(rootWidth);
    height: value(rootHeight);
}

.outerWrapper {
    width: value(wrapperWidth);
    height: value(wrapperHeight);
}

.text{
    display: block;
    text-align: center;
    font-family: Helvetica Neue W01 45 Light;
    white-space: nowrap;
    height: 100%;
    width: 100%;
    line-height: normal;
}

.root::innerContainer{
    min-width: 0px;
    min-height: 16px;
    gap: calc(value(spacing) * 1px);
    flex-direction: value(icon-position);
}

.root::icon{
    height: 16px;
    width: 16px;
    justify-content: center;
    flex-shrink: 0;
}

.root::icon svg {
    height: max(16px, 100%);
    width: max(16px, 100%);
}

