/7e255b213914cafb22c6441397b85fd649ab7ed.content:
:vars {
    DefaultItemSize: 24px;
    DefaultBorderRadius: 12px;
}

.root {
    -st-states: checked, focused, unavailable, focusedByKeyboard;
}

.root * {
    box-sizing: border-box;
}

.radioOuter {
    display: flex;
    justify-content: center;
    align-items: stretch;
    margin: 4px;
    width: value(DefaultItemSize);
    height: value(DefaultItemSize);
    border-radius: value(DefaultBorderRadius);
    padding: 2px;
}

.radioInner {
    position: relative;
    overflow: hidden;
    border-radius: inherit;
    border: 1px solid #C9C9C9;
    flex: 1;
}

.root:unavailable .radioInner::before {
    content: '';
    position: absolute;
    border-top: 1px solid #C9C9C9;
    transform-origin: center;
    transform: rotate(-45deg);
    width: 150%;
    left: -25%;
    top: 50%;
}

.root:checked .radioOuter {
    box-shadow: 0 0 0 1px #000000;
}

.root:disabled {
    filter: none;
    opacity: 1;
}

